CREATE RULE ri_extdata AS
    ON INSERT TO extdata DO INSTEAD  INSERT INTO extdatavalues (entity, field, index, value)
  VALUES (new.entity, f_extdatafields_upsert(new.entity, new.name::text), new.index, new.value);

CREATE RULE ri_tags AS
    ON INSERT TO tags DO INSTEAD  INSERT INTO tagrels (entity, name, index)
  VALUES (new.entity, f_tagnames_upsert(new.entity, new.name::text), new.index);
